using System;

class Program {
    static void Main() {
        int[][] triangle = new int[4][];
        for (int i = 0; i < 4; i++) {
            triangle[i] = new int[i + 1];
            for (int j = 0; j <= i; j++) {
                triangle[i][j] = i + j + 1;
            }
        }
        foreach (var row in triangle) {
            Console.WriteLine(string.Join(" ", row));
        }
    }
}

using System;

class Program {
    static void Main() {
        int[] source = { 1, 2, 3, 4, 5 };
        int[] dest = new int[5];
        Array.Copy(source, dest, 5);
        dest[0] = 99;
        Console.WriteLine(string.Join(" ", source)); // unchanged
        Console.WriteLine(string.Join(" ", dest));   // modified copy
    }
}
